  color: var(--color-text-muted, #9ca3af);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.projects-panel__add-form-add-btn[data-v-4d3b0895] {
  width: 28px;
  height: 28px;
  border-radius: 8px;
  border: 1px solid #4a90d9;
  background: #fff;
  color: #4a90d9;
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.15s;
  flex-shrink: 0;
}
.projects-panel__add-form-add-btn[data-v-4d3b0895]:hover:not(:disabled) {
  background: #4a90d9;
  color: #fff;
}
.projects-panel__add-form-add-btn[data-v-4d3b0895]:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
.projects-panel__add-form-spinner[data-v-4d3b0895] {
  width: 12px;
  height: 12px;
  border: 2px solid #4a90d9;
  border-top-color: transparent;
  border-radius: 50%;
  animation: projects-panel-spin-4d3b0895 0.8s linear infinite;
  display: inline-block;
}
@keyframes projects-panel-spin-4d3b0895 {
to { transform: rotate(360deg);
}
}
