  border: 1px solid #d0d5dd;
  border-radius: 8px;
  color: var(--color-text-secondary, #6b7280);
  cursor: pointer;
  font-size: 16px;
  width: 38px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.15s, color 0.15s, border-color 0.15s;
}
.members-panel__icon-btn[data-v-734aea2e]:hover:not(:disabled) {
  background: #f0f1f5;
  color: var(--color-text-primary, #1a1a2e);
  border-color: #b6bcc8;
}
.members-panel__icon-btn[data-v-734aea2e]:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
.members-panel__autogen[data-v-734aea2e] {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 12px;
  color: var(--color-text-secondary, #6b7280);
  margin-top: 6px;
  cursor: pointer;
  user-select: none;
}
.members-panel__autogen input[data-v-734aea2e] {
  margin: 0;
  cursor: pointer;
}
.members-panel__form-actions[data-v-734aea2e] {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  margin-top: 14px;
}
.members-panel__btn[data-v-734aea2e] {
  border: 1px solid transparent;
  border-radius: 8px;
  padding: 7px 14px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  transition: background 0.15s, color 0.15s, border-color 0.15s;
}
.members-panel__btn--ghost[data-v-734aea2e] {
  background: transparent;
  color: var(--color-text-secondary, #6b7280);
  border-color: #d0d5dd;
}
.members-panel__btn--ghost[data-v-734aea2e]:hover:not(:disabled) {
  background: #f0f1f5;
  color: var(--color-text-primary, #1a1a2e);
}
.members-panel__btn--primary[data-v-734aea2e] {
  background: #4a90d9;
  color: #fff;
  border-color: #4a90d9;
}
.members-panel__btn--primary[data-v-734aea2e]:hover:not(:disabled) {
  background: #3a7bc3;
  border-color: #3a7bc3;
}
.members-panel__btn[data-v-734aea2e]:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
.members-panel__spinner--inline[data-v-734aea2e] {
  width: 12px;
  height: 12px;
  border-width: 2px;
}

/* ── Credentials reveal card ────────────────────────────────────────── */
.members-panel__reveal[data-v-734aea2e] {
  background: #fff;
  border: 1px solid #eaecf0;
  border-radius: 8px;
  padding: 14px;
}
.members-panel__reveal-heading[data-v-734aea2e] {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  font-weight: 700;
  color: #067647;
  margin-bottom: 12px;
}
.members-panel__reveal-check[data-v-734aea2e] {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  background: #d1fadf;
  color: #067647;
  font-size: 11px;
  font-weight: 700;
}
.members-panel__reveal-row[data-v-734aea2e] {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 0;
  border-bottom: 1px solid #f3f4f6;
  font-size: 13px;
}
.members-panel__reveal-row[data-v-734aea2e]:last-of-type {
  border-bottom: none;
}
.members-panel__reveal-row--full[data-v-734aea2e] {
  justify-content: flex-end;
  border-bottom: none;
  padding-top: 8px;
}
.members-panel__reveal-label[data-v-734aea2e] {
  font-weight: 600;
  color: var(--color-text-secondary, #6b7280);
  width: 80px;
  flex-shrink: 0;
}
.members-panel__reveal-value[data-v-734aea2e] {
  flex: 1;
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  color: var(--color-text-primary, #1a1a2e);
  word-break: break-all;
}
.members-panel__reveal-btn[data-v-734aea2e] {
  background: #fff;
  border: 1px solid #d0d5dd;
  color: var(--color-text-secondary, #6b7280);
  border-radius: 6px;
  padding: 4px 10px;
  font-size: 11px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, color 0.15s, border-color 0.15s;
}
.members-panel__reveal-btn[data-v-734aea2e]:hover {
  background: #f0f1f5;
  color: var(--color-text-primary, #1a1a2e);
  border-color: #b6bcc8;
}
.members-panel__reveal-btn--wide[data-v-734aea2e] {
  padding: 6px 14px;
  font-size: 12px;
}
.members-panel__reveal-warning[data-v-734aea2e] {
  margin: 12px 0 0;
  font-size: 11px;
  color: #b54708;
  background: #fef0c7;
  border: 1px solid #fec84b;
  border-radius: 6px;
  padding: 6px 10px;
  line-height: 1.4;
}
.members-panel__reveal-actions[data-v-734aea2e] {
  display: flex;
  justify-content: flex-end;
  margin-top: 12px;
}
